Create src/analyzers/node.py implementing BaseAnalyzer:
  async def analyze(self, k8s_state) -> List[Finding]:
      findings = []
      for node in k8s_state['nodes']:
          for cond in node.status.conditions:
              if cond.type in ('MemoryPressure','DiskPressure','PIDPressure') and cond.status == 'True':
                  findings.append(Finding(severity='high', title=cond.type, resource=node.metadata.name, ...))
              if cond.type == 'Ready' and cond.status != 'True':
                  findings.append(Finding(severity='critical', title='NodeNotReady', ...))
      return findings

Create src/analyzers/deployment.py implementing BaseAnalyzer:
  async def analyze(self, k8s_state) -> List[Finding]:
      findings = []
      for dep in k8s_state['deployments']:
          desired = dep.spec.replicas or 0
          available = dep.status.available_replicas or 0
          if available < desired:
              findings.append(Finding(severity='high', title='ReplicaMismatch', evidence={'desired': desired, 'available': available}, ...))
          for cond in (dep.status.conditions or []):
              if cond.type == 'Progressing' and cond.reason == 'ProgressDeadlineExceeded':
                  findings.append(Finding(severity='critical', title='RolloutStuck', ...))
      return findings
